e(['message'=>'شماره موبایل معتبر نیست.'],['intended_http_status'=>422]),200); $r=OtpStore::verify($m,$otp); if(!$r['ok'])wp_send_json_error(['message'=>$r['message'],'intended_http_status'=>422],200); $us=new UserService();$u=$us->findByMobile($m); if($u instanceof \WP_User){$us->login($u);Logger::add('info','User logged in',['mobile'=>$m]);wp_send_json_success(['status'=>'logged_in','redirect'=>Helpers::safeRedirect($this->afterLogin())]);} wp_send_json_success(['status'=>'needs_register','register_token'=>OtpStore::issueRegisterToken($m)]);} public function completeRegister():void{$this->check();$token=sanitize_text_field((string)($_POST['register_token']??''));$m=OtpStore::consumeRegisterToken($token); if(!$m)wp_send_json_error(array_merge(['message'=>'جلسه ثبت‌نام منقضی شده است. دوباره تلاش کنید.'],['intended_http_status'=>403]),200); $first=sanitize_text_field((string)($_POST['first_name']??''));$last=sanitize_text_field((string)($_POST['last_name']??''));$nc=Helpers::national((string)($_POST['national_code']??'')); if(Options::yes('require_first_last')){if(mb_strlen($first)<2)wp_send_json_error(array_merge(['message'=>'نام را صحیح وارد کنید.'],['intended_http_status'=>422]),200);if(mb_strlen($last)<2)wp_send_json_error(array_merge(['message'=>'نام خانوادگی را صحیح وارد کنید.'],['intended_http_status'=>422]),200);} if(Options::yes('require_national_code')){if(!Helpers::isValidNationalCode($nc))wp_send_json_error(array_merge(['message'=>'کد ملی معتبر نیست.'],['intended_http_status'=>422]),200); if(Options::yes('identity_required')){$p=ProviderRegistry::instance()->identity((string)Options::get('identity_provider','jibit'));$id=$p?$p->verifyOwner($m,$nc):['ok'=>false,'error'=>'ارائه‌دهنده تطبیق تنظیم نشده است.','error_code'=>'missing']; if(!$id['ok'])wp_send_json_error(['message'=>$id['error'],'error_code'=>$id['error_code'],'intended_http_status'=>503],200); if(!$id['matched'])wp_send_json_error(array_merge(['message'=>'کد ملی با شماره همراه تطابق ندارد.'],['in